import{_ as i,o as l,c as e,a3 as t}from"./chunks/framework.gsMzR_Kb.js";const u=JSON.parse('{"title":"阴阳","description":"易经最基础的分化关系，也是后续几乎所有判断的起点。","frontmatter":{"title":"阴阳","description":"易经最基础的分化关系，也是后续几乎所有判断的起点。","category":"concept","aliases":["阴阳","易经阴阳","yin yang"]},"headers":[],"relativePath":"yijing/basics/concepts/yin-yang.md","filePath":"yijing/basics/concepts/yin-yang.md","lastUpdated":1777132262000}'),n={name:"yijing/basics/concepts/yin-yang.md"};function o(r,a,s,c,h,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="阴阳" tabindex="-1">阴阳 <a class="header-anchor" href="#阴阳" aria-label="Permalink to &quot;阴阳&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>在《易经》语境里，阴阳不是两个互相敌对的抽象名词，而是一对最基本的关系词。</p><p>可以先把它理解成：</p><ul><li>一开一合</li><li>一显一藏</li><li>一动一应</li><li>一升一降</li><li>一刚一柔的起点</li></ul><p>它描述的不是静止标签，而是事物在关系中的分化、互感与流动。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>把阴阳读成简单的“好 / 坏”二分</li><li>把阴阳读成永远固定不变的属性</li><li>只把阴阳当神秘符号，而不回到具体关系里理解</li></ul><p>更稳的读法是：阴阳不是价值判断，而是观察结构、位置、势态与变化的一种方式。</p><h2 id="在原典中的语境" tabindex="-1">在原典中的语境 <a class="header-anchor" href="#在原典中的语境" aria-label="Permalink to &quot;在原典中的语境&quot;">​</a></h2><ul><li>《系辞》里反复谈“一阴一阳之谓道”，强调阴阳不是孤立存在，而是在往来中成其为道。</li><li>《说卦》与卦象系统里，阴阳首先表现为爻画、上下、动静、内外等结构关系。</li><li>在逐卦阅读时，阴阳也常与刚柔、中正、应位一起出现，不能单独拆开看。</li></ul><h2 id="我的理解" tabindex="-1">我的理解 <a class="header-anchor" href="#我的理解" aria-label="Permalink to &quot;我的理解&quot;">​</a></h2><p>待补：后续可结合具体卦例，把自己读到的“阴阳不是二元对立，而是动态关系”继续写进去。</p><h2 id="关联页面" tabindex="-1">关联页面 <a class="header-anchor" href="#关联页面" aria-label="Permalink to &quot;关联页面&quot;">​</a></h2><ul><li><a href="/Dao/yijing/basics/concepts/gang-rou">刚柔</a></li><li><a href="/Dao/yijing/basics/concepts/bian-yi">变易</a></li><li><a href="/Dao/yijing/basics/concepts/xiang-li-yong">象理用</a></li><li><a href="/Dao/topics/yin-yang">专题：阴阳</a></li></ul><h2 id="参考来源" tabindex="-1">参考来源 <a class="header-anchor" href="#参考来源" aria-label="Permalink to &quot;参考来源&quot;">​</a></h2><ul><li>《周易》</li><li>《系辞上传》</li><li>《说卦传》</li></ul>',17)])])}const b=i(n,[["render",o]]);export{u as __pageData,b as default};
